mapper.insert:
INSERT
  INTO
       MARKET_MEMBER
VALUES
       (
       SEQ_MEMBER_NO.NEXTVAL
     , #{memberId}
     , #{memberPwd}
     , #{memberName}
     , #{email}
     , #{phoneNumber}
     , #{address}
     , SYSDATE
     , SYSDATE
     , 'N'
       )

mapper.update:
UPDATE
       MARKET_MEMBER
   SET
       EMAIL = #{email}
     , PHONE_NUMBER = #{phoneNumber}
     , ADDRESS = #{address}
     , MODIFY_DATE = SYSDATE
 WHERE
       MEMBER_NO = #{memberNo}
   AND
       STATUS = 'N'
